import { useState, useEffect, useMemo, useCallback } from 'react';

/**
 * Custom hook for managing WorkflowGridManager state
 * Handles time period filtering, filter management, and data filtering
 */
export const useWorkflowGridState = ({ rowData, filterData, initialTimePeriod }) => {
  // Map API codes to internal values (reverse mapping)
  const timePeriodApiToInternalMap = {
    'All': 'all',
    '30D': '30days',
    '60D': '60days',
    '120D': '120days',
    '1Y': '1year'
  };
  
  // Convert API value to internal value if needed
  const getInitialTimePeriod = useCallback(() => {
    if (!initialTimePeriod || initialTimePeriod === 'all') return 'all';
    return timePeriodApiToInternalMap[initialTimePeriod] || initialTimePeriod;
  }, [initialTimePeriod]);

  // Time period state
  const [selectedTimePeriod, setSelectedTimePeriod] = useState(getInitialTimePeriod());
  const [timePeriodAnchorEl, setTimePeriodAnchorEl] = useState(null);
  const [timePeriodSearch, setTimePeriodSearch] = useState('');

  // Filter management state
  const [manageFiltersAnchorEl, setManageFiltersAnchorEl] = useState(null);
  const [filters, setFilters] = useState(
    filterData.length > 0 ? filterData : []
  );

  // Filtered row data
  const [filteredRowData, setFilteredRowData] = useState(rowData);

  // Time period filter options
  const timePeriodOptions = [
    { value: 'all', label: 'All' },
    { value: '30days', label: '30 Days' },
    { value: '60days', label: '60 Days' },
    { value: '120days', label: '120 Days' },
    { value: '1year', label: '1 Year' }
  ];

  // Filter data based on time period
  const filterDataByTimePeriod = useCallback((data, period) => {
    if (period === 'all') {
      return data;
    }

    const now = new Date();
    let startDate = new Date();

    switch (period) {
      case '30days':
        startDate.setDate(now.getDate() - 30);
        break;
      case '60days':
        startDate.setDate(now.getDate() - 60);
        break;
      case '120days':
        startDate.setDate(now.getDate() - 120);
        break;
      case '1year':
        startDate.setFullYear(now.getFullYear() - 1);
        break;
      default:
        return data;
    }

    return data.filter(item => {
      // Check multiple possible date field names (backend uses CreateDate, serialized as createDate or CreateDate)
      const itemDate = new Date(item.CreateDate || item.createDate || item.CreatedDate || item.DateCreated || item.Created || item.date);
      return itemDate >= startDate && itemDate <= now;
    });
  }, []);

  // Update filtered data when time period changes
  useEffect(() => {
    const filtered = filterDataByTimePeriod(rowData, selectedTimePeriod);
    setFilteredRowData(filtered);
  }, [rowData, selectedTimePeriod, filterDataByTimePeriod]);

  // Update filters when filterData prop changes (only on initial load or when IDs change)
  useEffect(() => {
    if (filterData.length > 0) {
      const currentIds = filters.map(f => f.id).sort().join(',');
      const newIds = filterData.map(f => f.id).sort().join(',');
      if (currentIds !== newIds) {
        setFilters(filterData);
      }
    }
  }, [filterData]);

  // Sync initialTimePeriod prop to state when it changes
  useEffect(() => {
    const newTimePeriod = !initialTimePeriod || initialTimePeriod === 'all'
      ? 'all'
      : (timePeriodApiToInternalMap[initialTimePeriod] || initialTimePeriod);
    setSelectedTimePeriod(newTimePeriod);
  }, [initialTimePeriod]);

  // Filter options based on search
  const filteredTimePeriodOptions = useMemo(() => {
    if (!timePeriodSearch) return timePeriodOptions;
    return timePeriodOptions.filter(option => 
      option.label.toLowerCase().includes(timePeriodSearch.toLowerCase())
    );
  }, [timePeriodOptions, timePeriodSearch]);

  return {
    // Time period state
    selectedTimePeriod,
    setSelectedTimePeriod,
    timePeriodAnchorEl,
    setTimePeriodAnchorEl,
    timePeriodSearch,
    setTimePeriodSearch,
    timePeriodOptions,
    filteredTimePeriodOptions,
    
    // Filter management state
    manageFiltersAnchorEl,
    setManageFiltersAnchorEl,
    filters,
    setFilters,
    
    // Filtered data
    filteredRowData,
    setFilteredRowData,
    
    // Helper
    filterDataByTimePeriod
  };
};

