import { useCallback, useMemo } from 'react';

/**
 * Custom hook for managing WorkflowGridManager handlers
 * Handles all user interactions and API calls
 */
export const useWorkflowGridHandlers = ({
  rowData,
  onRowDataChange,
  onCreateFilterClick,
  setFilteredRowData,
  setSelectedTimePeriod,
  setFilters,
  filters,
  setTimePeriodAnchorEl,
  setManageFiltersAnchorEl,
  setTimePeriodSearch,
  filterDataByTimePeriod,
  timePeriodSearch,
  filterType,
  /** If provided, called instead of window.confirm; (filter, performDelete) => void. Use for custom modal. */
  onShowDeleteConfirm = null
}) => {

  // Time period handlers
  const handleTimePeriodClick = useCallback((event) => {
    setTimePeriodAnchorEl(event.currentTarget);
  }, [setTimePeriodAnchorEl]);

  const handleTimePeriodClose = useCallback(() => {
    setTimePeriodAnchorEl(null);
    setTimePeriodSearch('');
  }, [setTimePeriodAnchorEl, setTimePeriodSearch]);

  // Handle radio button selection
  const handleTimePeriodChange = useCallback((event) => {
    const newTimePeriod = event.target.value;
    
    // Update state immediately for UI feedback
    setSelectedTimePeriod(newTimePeriod);
    handleTimePeriodClose();
    
    // Filter data locally - no page reload needed!
    if (filterDataByTimePeriod) {
      const filtered = filterDataByTimePeriod(rowData, newTimePeriod);
      setFilteredRowData(filtered);
    }
    
    // Call the UpdateUISetting API to persist the preference (fire and forget - no page reload)
    const timePeriodCodeMap = {
      'all': 'All',
      '30days': '30D',
      '60days': '60D',
      '120days': '120D',
      '1year': '1Y'
    };
    
    const timePeriodCode = timePeriodCodeMap[newTimePeriod] || newTimePeriod;
    
    // Persist preference in background - don't block UI or reload page
    fetch('/User/UpdateUISetting', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({ key: 'TimePeriodCode', value: timePeriodCode })
    })
    .then(response => response.json())
    .then(data => {
      if (!data || !data.success) {
        console.warn('Failed to persist time period preference:', data?.message);
        // Note: Don't revert state - local filtering already applied successfully
      }
    })
    .catch(error => {
      console.warn('Error persisting time period preference:', error);
      // Note: Don't revert state - local filtering already applied successfully
    });
  }, [setSelectedTimePeriod, handleTimePeriodClose, filterDataByTimePeriod, rowData, setFilteredRowData]);

  // Manage filters handlers
  const handleManageFiltersClick = useCallback((event) => {
    setManageFiltersAnchorEl(event.currentTarget);
  }, [setManageFiltersAnchorEl]);

  const handleManageFiltersClose = useCallback(() => {
    setManageFiltersAnchorEl(null);
  }, [setManageFiltersAnchorEl]);

  // Handle filter edit
  const handleFilterEdit = useCallback((filterId) => {
    // Find the filter by ID
    const filter = filters?.find(f => f.id === filterId);
    
    // Convert actualId to number and validate it's a positive integer
    const actualIdNum = parseInt(filter?.actualId, 10);
    const hasValidId = !isNaN(actualIdNum) && actualIdNum > 0;
    
    // Check if this is the "All Workflows" filter which cannot be edited
    const isAllWorkflows = filter?.name === 'All Workflows';
    
    if (filter && hasValidId && !isAllWorkflows) {
      // Open filter editor modal with the selected filter for editing
      // Use the filterType passed from props, default to workflow if not specified
      const editorFilterType = filterType || 'SecurimateWorkItemFilterGroup';
      
      // Helper function to initialize the filter editor
      const initEditor = () => {
        // Remove any existing filter editor container
        const existingContainer = document.getElementById('filter-editor');
        if (existingContainer) {
          existingContainer.remove();
        }
        
        // Create container div for FilterEditor (it expects id="filter-editor")
        const filterEditorContainer = document.createElement('div');
        filterEditorContainer.id = 'filter-editor';
        // Set up container with backdrop overlay
        filterEditorContainer.style.position = 'fixed';
        filterEditorContainer.style.top = '0';
        filterEditorContainer.style.left = '0';
        filterEditorContainer.style.right = '0';
        filterEditorContainer.style.bottom = '0';
        filterEditorContainer.style.zIndex = '99999';
        filterEditorContainer.style.backgroundColor = 'rgba(0, 0, 0, 0.5)'; // Backdrop
        filterEditorContainer.style.display = 'flex';
        filterEditorContainer.style.alignItems = 'baseline';
        filterEditorContainer.style.justifyContent = 'center';
        filterEditorContainer.style.paddingTop = '20px';
        document.body.appendChild(filterEditorContainer);
        
        // Create a minimal fake Bootstrap modal element to prevent FilterEditorRoot errors
        let fakeModal = document.getElementById('filter-editor-modal');
        if (!fakeModal) {
          fakeModal = document.createElement('div');
          fakeModal.id = 'filter-editor-modal';
          fakeModal.className = 'modal fade';
          fakeModal.style.display = 'none';
          document.body.appendChild(fakeModal);
        }
        
        // Close handler - remove container when closed
        const closeFilterEditorHandler = () => {
          const container = document.getElementById('filter-editor');
          if (container) {
            // Unmount React component
            try {
              if (container._reactRootContainer) {
                container._reactRootContainer.render(null);
              } else if (window.ReactDOM && window.ReactDOM.unmountComponentAtNode) {
                window.ReactDOM.unmountComponentAtNode(container);
              }
            } catch (e) {
              console.warn('Error unmounting FilterEditor:', e);
            }
            // Remove container
            container.remove();
          }
        };
        
        // Set up Bootstrap modal event handler for cleanup
        if (window.jQuery && window.jQuery('#filter-editor-modal').length) {
          window.jQuery('#filter-editor-modal').off('hidden.bs.modal').on('hidden.bs.modal', closeFilterEditorHandler);
        }
        
        // Initialize filter editor with filterGroupId for edit mode
        // filterGroupId must be passed as a string to match the expected format
        window.initializeFilterEditor({
          filterGroupId: String(actualIdNum),
          filterType: editorFilterType,
          hideRuntimeOption: true
        });
      };
      
      // Wait for initializeFilterEditor to be available (script might still be loading)
      const checkAndInitialize = (attempts) => {
        const maxAttempts = 20; // Wait up to 2 seconds (20 * 100ms)
        
        if (window.initializeFilterEditor && typeof window.initializeFilterEditor === 'function') {
          initEditor();
        } else if (attempts < maxAttempts) {
          setTimeout(() => checkAndInitialize(attempts + 1), 100);
        } else {
          alert('Unable to open filter editor. Please refresh the page and try again.');
        }
      };
      
      // Start checking for initializeFilterEditor
      checkAndInitialize(0);
    } else if (isAllWorkflows) {
      console.warn('Cannot edit filter: "All Workflows" filter is not editable');
    } else {
      console.warn('Cannot edit filter: filter ID or actualId not found or invalid', filterId, filter?.actualId);
    }
  }, [filters]);

  // Handle filter delete (uses custom modal when onShowDeleteConfirm provided, else browser confirm)
  const handleFilterDelete = useCallback((filterId) => {
    const filter = filters?.find(f => f.id === filterId);
    if (!filter) {
      console.warn('Filter not found:', filterId);
      return;
    }
    if (filter.enabled || !filter.actualId || filter.name === 'All Workflows') {
      console.warn('Cannot delete filter: filter is enabled, has no actualId, or is "All Workflows"');
      return;
    }

    const performDelete = () => {
      const deleteUrl = `/Filter/Delete?filterGroupId=${filter.actualId}`;
      fetch(deleteUrl, { method: 'GET' })
        .then(response => {
          if (response.ok || response.redirected) {
            setFilters(prev => prev.filter(f => f.id !== filterId));
            window.location.reload();
          } else {
            return response.text().then(text => {
              throw new Error(text || 'Failed to delete filter');
            });
          }
        })
        .catch(error => {
          console.error('Error deleting filter:', error);
          alert('Error deleting filter. Please try again.');
        });
    };

    if (typeof onShowDeleteConfirm === 'function') {
      onShowDeleteConfirm(filter, performDelete);
    } else if (window.confirm(`Are you sure you want to delete the filter "${filter.name}"?`)) {
      performDelete();
    }
  }, [filters, setFilters, onShowDeleteConfirm]);

  // Create filter handler
  const handleCreateFilterClick = useCallback(() => {
    if (onCreateFilterClick) {
      onCreateFilterClick();
    } else {
      // Default: Navigate to filter creation page
      window.location.href = '/Filter/Create';
    }
  }, [onCreateFilterClick]);

  // Memoize the return object to prevent unnecessary re-renders in consumers
  return useMemo(() => ({
    handleTimePeriodClick,
    handleTimePeriodClose,
    handleTimePeriodChange,
    handleManageFiltersClick,
    handleManageFiltersClose,
    handleFilterEdit,
    handleFilterDelete,
    handleCreateFilterClick
  }), [
    handleTimePeriodClick,
    handleTimePeriodClose,
    handleTimePeriodChange,
    handleManageFiltersClick,
    handleManageFiltersClose,
    handleFilterEdit,
    handleFilterDelete,
    handleCreateFilterClick
  ]);
};

